INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989469","title":"Мстители: Железный человек","author":"Пол Тобин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005054511/140/44ca/Pol_Tobin__Mstiteli_Zheleznyj_chelovek.jpg","isbn":"978-5-17-119859-6","publisher":"АСТ","pubDate":"2020","language":"Русский","series":"Вселенная Марвел. Приключения","genres":[],"annotation":"Не всякая угроза по плечу человечеству. Компания могучих бойцов готова рисковать жизнью, чтобы всех защитить!  Это Железный Человек, Вижн, Капитан Америка, Невидимая Леди, Тор, Чёрная Вдова, Нова.  Они - супергерои \"Мстители\"!  В этом комиксе они столкнуться со злодеяниями Магнето и его Братства мутантов, Галактуса, Алмазоголова и Филина, Красного Призрака и его супермартышек, а также Крэйвена Охотника. В качестве приглашённой звезды - известный болтливый наёмник Дэдпул.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999465,"hdCover":""},{"id":"0989468","title":"Человек-Паук: Удивительная фантазия","author":"Пол Тобин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004043487/140/a728/Pol_Tobin__ChelovekPauk_Udivitelnaya_fantaziya.jpg","isbn":"978-5-17-119856-5","publisher":"АСТ","pubDate":"2020","language":"Русский","series":"Вселенная Марвел. Приключения","genres":["Комиксы","манга","графические романы"],"annotation":"Самого обыкновенного подростка укусил радиоактивный паук. И вот так парень получил суперспособности. Но однажды он повёл себя глупо и эгоистично и в результате потерял дорогого человека. Теперь он делает всё, чтобы искупить вину. Его зовут Питер Паркер, но вы можете звать его Человек-Паук! В этом комиксе на его пути встанет множество злодеев: мастер магнетизма Магнето, коварный Хамелеон, злобный Мандарин, чудной Человек-Лягушка, злобный МОДОК, надоедливый Кукловод, мерзкий Поглотитель и расчётливый Кингпин! А в качестве приглашённых звёзд – очаровательные Блондинка Фантом и Чёрная Кошка!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999464,"hdCover":""},{"id":"0989467","title":"Дора","author":"Аня Смирнова","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002874753/140/a97b/Anya_Smirnova__Dora.jpg","isbn":"978-5-99093-677-5,  978-5-99093-678-2","publisher":"КомФедерация","pubDate":"2018","language":"Русский","series":"Отечественные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Три главы этого комикса рассказывают о событиях осени, зимы и весны из жизни девятиклассницы Доры, которая только что сменила школу. Дора страдает от всего, от чего страдает каждый подросток. Её частенько заносит на поворотах, но она старается, учится задумываться о последствиях своих действий, преодолевать трудности и ценить настоящую дружбу. Эта книга является дебютной работой иллюстратора Ани Смирновой, также известной как Anya Conservi, и затрагивает темы, не так часто встречающиеся на страницах отечественных комиксов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2,"review":"","added":9999463,"hdCover":""},{"id":"0989466","title":"Антисоциальный клуб","author":"Елена Маликова","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003175459/140/95ad/Elena_Malikova__Antisotsialnyj_klub.jpg","isbn":"978-5-91339-861-1","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Школьные годы далеко не всегда оказываются такими уж чудесными, как любят говорить взрослые. Например, Еву дразнят в школе из-за её протеза, заменяющего руку. Над Женей смеются просто потому, что он увлекается комиксами. Ася стала объектом насмешек из-за якобы лишнего веса, а Никиту травят по причине того, что он из небогатой семьи. Каждый день ребята подвергаются унижениям со стороны школьных хулиганов и кажется, этому не будет конца. Но однажды загадочный Леон собирает их вместе в некий \"\"Антисоциальный клуб\"\", обещая помочь. Вместе им предстоит познать цену дружбы и научиться давать отпор обидчикам… Если только страхи и обиды не порушат их хрупкий союз.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2,"review":"","added":9999462,"hdCover":""},{"id":"0989465","title":"Игорь Угорь. Том 2. Икра","author":"Е. Еронин,Роман Котков,Анастасия Ким,Евгений Еронин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003009288/140/bc34/__Igor_Ugor._Tom_2._Ikra.jpg","isbn":"978-5-6041511-7-4","publisher":"Bubble Comics","pubDate":"2019","language":"Русский","series":"2021","genres":["Комиксы","манга","графические романы"],"annotation":"«ИГОРЬ УГОРЬ 2: ИКРА» — любимейший, шикарный, неповторимый! 62 страницы чистого великолепия с обложкой от Анастасии Phobs Ким. Наконец-то каждый желающий сможет прикоснуться к легенде.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999461,"hdCover":""},{"id":"0989464","title":"Ultimate Comics Avengers: Crime and Punishment","author":"Марк Миллар,Лейнил Фрэнсис Ю","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001847841/140/f0cc/__Ultimate_Comics_Avengers_Crime_and_Punishment.jpg","isbn":"9780785136712","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Some jobs are just too dirty for the Ultimates. For these, Nick Fury must gather the Avengers, a black ops team willing to do the missions that others won''t. What role will an infamous mass killer play in Fury''s plans? Find out, as the Punisher returns to the Ultimate U! Blockbuster team of MARK MILLAR (ULTIMATES) and LEINIL YU (SECRET INVASION) present the explosive tale. Collecting: Ultimate Avengers 2 #1-6","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999460,"hdCover":""},{"id":"0989463","title":"Хальмстад","author":"Джазендапус","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002996017/140/914b/Dzhazendapus__Halmstad.jpg","isbn":"978-5-6043395-5-8","publisher":"Jellyfish Jam","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Холодная осень в скандинавском Хальмстаде — время, когда кровь не только стынет в жилах, но и проливается на улицах. Здесь сталкиваются боги и люди, предательство подстерегает в самом ближнем кругу, а тайное становится явным и приводит к самым страшным последствиям.  «Хальмстад» Алексея Герасимова, более известного под именем ДЖАЗЕНДАПУС («Горилла Фрэнсис», «Славик нигилизм 2.99») — это вольная адаптация испанской легенды об Альмамуле и одновременно актуальное высказывание о домашнем насилии. Но, главное, это настоящий визуальный взрыв и штурм ваших глаз, где не знаешь чего ждать, переворачивая страницу. Ни одно цветовое пятно, ни одна буква уникальной ручной типографики здесь не случайны, всё помогает рассказать страшную историю Хальмстада.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3.5,"review":"","added":9999459,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989462","title":"Игорь Угорь. Том 1","author":"Роман Котков,Артем Габрелянов,Анастасия Ким,Евгений Еронин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002236821/140/c507/__Igor_Ugor._Tom_1.jpg","isbn":"978-5-9908710-9-0","publisher":"Bubble","pubDate":"2017","language":"Русский","series":"Игорь Угорь","genres":["Комиксы","манга","графические романы"],"annotation":"Это драматичная и полная удивительных сюжетных поворотов история из альтернативной вселенной, в которой майор Игорь Гром оказывается не человеком… а угрём... Но разве это помешает ему бороться с преступностью... ну, по мере сил угря!  Над комиксом работал практически весь звёздный состав издательства и специально приглашённые гости, а автором обложки и содержимого книги выступила Анастасия Phobs Ким! Не пропустите захватывающую приключенческую книгу «Игорь Угорь» - одну из главных новинок года!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3,"review":"","added":9999458,"hdCover":""},{"id":"0989461","title":"Что если бы Алый Паук убил бы Человека-Паука?","author":"","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003506346/140/e80a/bez_avtora__Chto_esli_by_Alyj_Pauk_ubil_by_ChelovekaPauka.jpg","isbn":"978-5-6043356-0-4","publisher":"Другое издательство","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Суперзлодей Шакал запрограммировал разум Человека-Паука на убийство его жены Мэри Джейн. Чтобы спасти ее, Алый Паук, клон Питера Паркера, вынужден убить Человека-Паука!  Чем обернется такой поступок? Сможет ли Алый Паук занять место Питера? И какую роль во всем этом играет Зеленый Гоблин?  Узнайте все это из классического выпуска серии «Что если?», рассказывающего альтернативную версию одного из ключевых периодов в истории Marvel — «Саги о клонах».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999457,"hdCover":""},{"id":"0989460","title":"Росомаха","author":"Фрэнк Миллер,Крис Клэрмонт,Пол Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002267304/140/f75a/__Rosomaha.jpg","isbn":"978-5-91339-513-9","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Росомаха летит на Восток по зову сердца, но находит лишь ярость! Униженный в битве перед Марико Яшида, Росомаха направляет свою злобу против «Руки», а страсть его находит прибежище у Юкио, девушки, жаждующей битв! Ведя внутреннюю борьбу человека против зверя, что сидят в нём, он должен решить, кто из них поможет ему одолеть врагов и вернуть любимую в своей первой сольной серии!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999456,"hdCover":""},{"id":"098945f","title":"Batman: The Three Jokers","author":"Джефф Джонс,Джейсон Фабок","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005507028/140/7f3d/__Batman_The_Three_Jokers.jpg","isbn":"9781779500236","publisher":"DC Black Label","pubDate":"2020","language":"Английский","series":"","genres":[],"annotation":"30 years after \"The Killing Joke\" changed comics forever, \"The Three Jokers\" re-examines the myth of who, or what, is the Joker and what is at the heart of his ongoing battle with Batman? New York Times bestselling writer Geoff Johns and Jason Fabok, the writer/artist team that waged the \"Darkseid War\" in the pages of Justice League, reunite to tell the ultimate story of Batman and The Joker!  After years of anticipation, the epic story is finally here: find out why there are three Jokers, and what that means for the decades-long battle between the Dark Knight and the Clown Prince of Crime. In this powerful, emotional story Batman, Batgirl and Red Hood - all past victims of the Joker - work together to solve a mystery unlike anything they''ve ever faced before!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3,"review":"","added":9999455,"hdCover":""},{"id":"098945e","title":"Daredevil: The Man Without Fear","author":"Frank Miller,Romita John, Jr.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001257660/140/b767/__Daredevil_The_Man_Without_Fear.jpg","isbn":"0785134794,  978-0785134794","publisher":"Marvel","pubDate":"1993","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"A fire burns deep within Matt Murdock. He was raised by a single father, an over-the-hill prizefighter with one last chance to make it good - a chance that cost him his life. Taunted and tormented by children while growing up, Matt''s life was irrevocably altered after he was blinded by radioactive materials while saving the life of an old man. The payoff? An unbreakable will and a keen intelligence, helping focus the super-senses he was blessed with during the accident. His story is one of love, pain, disappointment, and strength. Witness the tour-de-force origin of the Man Without Fear by industry legends Frank Miller and John Romita Jr. Collects Daredevil: The Man Without Fear #1-5.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4.5,"review":"","added":9999454,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098945d","title":"Супергерои Марвел. Выпуск 6. Сорвиголова","author":"Фрэнк Миллер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002984858/140/9931/Frenk_Miller__Supergeroi_Marvel._Vypusk_6._Sorvigolova.jpg","isbn":"9772619134308-006","publisher":"Hachette","pubDate":"2019","language":"Русский","series":"Супергерои Марвел. Официальная коллекция.","genres":[],"annotation":"Мэтт Мёрдок слеп, но его другие чувства развиты до сверхчеловеческого уровня. Он - сорвиголова, Человек без страха. Прочтите, как всё началось в \"Сорвиголова\" #1 Стэна Ли и Билла Эверетта, а затем одну из величайших историй Marvel Comics - \"Сорвиголова: Человек без страха\". Погрузитесь в историю происхождения одного из величайших супергероев Marvel от Фрэнка Миллер и Джона Ромиты-младшего. Узнайте, как юный мальчик стал легендарным борцом с преступностью на улицах Адской кухни в сборнике \"Величайшие герои Marvel: Сорвиголова\"!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4.5,"review":"","added":9999453,"hdCover":""},{"id":"098945c","title":"Сорвиголова Фрэнка Миллера и Клауса Янсона. Том 3","author":"Фрэнк Миллер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005449485/140/0f65/Frenk_Miller__Sorvigolova_Frenka_Millera_i_Klausa_Yansona._Tom_3.jpg","isbn":"978-5-04-110027-8","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"На страницах третьего (и заключительного!) тома о приключениях Человека без страха, легенды комикс-индустрии Фрэнк Миллер и Клаус Янсон подготовят для Сорвиголовы воистину смертельные испытания! Ведь за его учителем Стиком охотится клан ниндзя \"Рука\", а Мэтт Мёрдок ничем не может ему помочь, ведь его способности вышли из-под контроля! Так что Стику сначала придётся выручать Дьявола Адской кухни, а потом уже вербовать его в свою команду! Но и это не всё! Фогги Нельсон опустится на самое дно преступного мира и встретится лицом к лицу с Кингпином, а на улицы Нью-Йорка выйдет единственный герой, которого уважают меньше, чем Ходульника… Второй Ходульник! Хизер Гленн будет бороться за бизнес отца, а Чёрная Вдова за свою жизнь! Как вы думаете, Электра появится в этой истории? После вы узнаете, сможет ли молчаливый рыжеволосый незнакомец навести порядок в небольшом городке, и что было бы, если Мэтт Мёрдок стал агентом ЗАЩИТы. А в самом конце вас ждёт удивительный графический роман \"Любовь и война\" маэстро Фрэнка Миллера и настоящего волшебника Билла Сенкевича! Не стоит забывать и о обширных дополнительных материалах! Поверьте, перед вами издание, достойно завершающее легендарную серию!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":5,"review":"","added":9999452,"hdCover":""},{"id":"098945b","title":"Daredevil: Love and War","author":"Фрэнк Миллер,Билл Сенкевич","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000461000/140/d1c3/__Daredevil_Love_and_War.jpg","isbn":"978-0871351722","publisher":"Marvel Enterprises","pubDate":"1990","language":"","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999451,"hdCover":""},{"id":"098945a","title":"Дэдпул уничтожает вселенную Marvel","author":"Каллен Банн,Далибор Таладжич","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001390816/140/d457/__Dedpul_unichtozhaet_vselennuyu_Marvel.jpg","isbn":"978-5-91339-328-9","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":2,"review":"","added":9999450,"hdCover":""},{"id":"0989459","title":"Essential Daredevil Volume 2 TPB","author":"Стэн Ли,Джин Колан","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000137813/140/147f/__Essential_Daredevil_Volume_2_TPB.jpg","isbn":"0785114629","publisher":"Marvel Comics","pubDate":"2004","language":"Английский","series":"Marvel Essentials","genres":["Зарубежное фэнтези"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999449,"hdCover":""},{"id":"0989458","title":"Сорвиголова. Рождённый заново","author":"Фрэнк Миллер, Дэвид Маццукелли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002311175/140/9883/Frenk_Miller_Devid_Matstsukelli__Sorvigolova._Rozhdjonnyj_zanovo.jpg","isbn":"978-5-91339-508-5","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Эпохальная история о Сорвиголове от легенд индустрии Фрэнка Миллера и Дэвида Маццукелли! Карен Пейдж, бывшая возлюбленная Мэтта Мёрдока, обменяла тайну личности Человека без Страха на дозу. В итоге Сорвиголове нужно найти в себе силы, ведь Главарь Преступного Мира не станет терять времени и превратит его жизнь в такой ад, который не снился ему и в самых страшных кошмарах.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999448,"hdCover":""},{"id":"0989457","title":"Essential Daredevil, Vol. 1","author":"Стэн Ли,Джин Колан,Wallace Wood,Джон Ромита-ст.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000297830/140/5b1a/__Essential_Daredevil_Vol._1.jpg","isbn":"0785118616","publisher":"Marvel Comics","pubDate":"2005","language":"Английский","series":"Marvel Essentials","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999447,"hdCover":""},{"id":"0989456","title":"Сорвиголова Фрэнка Миллера и Клауса Янсона. Том 2","author":"Фрэнк Миллер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003012326/140/4f06/Frenk_Miller__Sorvigolova_Frenka_Millera_i_Klausa_Yansona._Tom_2.jpg","isbn":"","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сорвиголова появился во вселенной Marvel в 1964 году, но важнейшим этапом его существования всё же стал ран сценариста/художника Фрэнка Миллера и художника/контуровщика Клауса Янсона. С 1979 по 1983 год Миллер буквально создал персонажа заново, при этом быстро став крупной и влиятельной фигурой в мире комиксов. Миллер видоизменил таких важных персонажей мира Сорвиголовы, как репортёр Бен Урих, роковая красотка Чёрная Вдова, безумный киллер Меченый, вооружённый пилами Гладиатор и могучий преступный босс Кингпин. Также Миллер представил читателям загадочного наставника Сорвиголовы Стика, смертоносных ниндзя из клана Руки, а также бывшую возлюбленную Мэтта Электру – прекрасную наёмницу, ставшую одной из самых запоминающихся героинь Marvel. Смешав традиционную супергероику с историями о боевых искусствах, обречённой любви и личных трагедиях, Миллер создал комиксы, определившие сущность Сорвиголовы. Второй том собрания этих комиксов вы и держите в руках!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4.5,"review":"","added":9999446,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989455","title":"Зеленая Стрела. Книга 2. Война Посторонних","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002704922/140/3993/Dzheff_Lemir__Zelenaya_Strela._Kniga_2._Vojna_Postoronnih.jpg","isbn":"978-5-389-12819-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Едва придя в себя после сражения с Графом Вертиго, Зеленая Стрела вновь отправляется на проклятый остров уже вместе с Шадо. Им нужна тотемная Стрела, за которой охотится Комодо. Только разыскав ее, они сумеют спасти сводную сестру Оливера – Эмико. Однако Квин и не подозревает, что на острове откроется правда, которую он предпочел бы не знать. Эта правда даст начало большой войне, войне Посторонних. Но кто же защищает Сиэтл, пока Оливер гоняется за призраками прошлого? Сумеют ли его друзья выстоять в схватке с Ричардом Драконом? Зеленая Стрела не может подвести город. Только не в этот раз.  Получивший высокие оценки сюжет, созданный высококлассной творческой командой сценариста ДЖЕФФА ЛЕМИРА («СЛАДКОЕЖКА») и художника АНДРЕА СОРРЕНТИНО («Я, ВАМПИР»), полностью переворачивает наше представление о Зеленой Стреле. В книгу включены выпуски: 1-й «Конец будущего. Зеленая Стрела», 4-й «Тайное происхождение. Зеленая Стрела», а также выпуски 27–34 «ЗЕЛЕНОЙ СТРЕЛЫ».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999445,"hdCover":""},{"id":"0989454","title":"Зеленая Стрела. Книга 1. Машина смерти (сборник)","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002463447/140/1f85/Dzheff_Lemir__Zelenaya_Strela._Kniga_1._Mashina_smerti_sbornik.jpg","isbn":"978-5-389-12680-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Шесть лет назад Оливер Квин оказался на таинственном острове, где погиб тот, кем он был прежде… и появился герой по имени Зеленая Стрела. Однако вскоре Оливеру предстоит узнать, что это суровое испытание не было случайностью.  Появление в Сиэтле нового лучника вынудит Оливера искать ответы по всему свету и снова приведет на остров, где все началось.  Могущественные силы уверены, что Оливер должен вернуться на остров, чтобы найти свое призвание. Что же он выберет: играть предназначенную ему роль или жить так, как он решил сам?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999444,"hdCover":""},{"id":"0989453","title":"The Boys, Vol. 9: The Big Ride","author":"Дэрик Робертсон,Гарт Эннис,Russ Braun,Джон Маккрэй","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003404279/140/6bd1/__The_Boys_Vol._9_The_Big_Ride.jpg","isbn":"978-1606902202","publisher":"Dynamite Entertainment","pubDate":"2011","language":"","series":"The Boys Book Series","genres":[],"annotation":"All the pieces are falling into place, for the Boys as well as their most mortal enemies. The long-dreaded superhuman conflict is on its way. But first there are secrets still to be uncovered: like the story of the team''s first encounter with supergroup The Seven, and the shockwaves from that disastrous meeting that still reverberate today. Hughie, meanwhile, discovers his comrades'' hidden history, as their original leader Colonel Greg Mallory takes him through sixty years of the filthiest black operations imaginable. And finally, with good and bad guys teetering on the brink, a shadowy force sets events in motion that will push even Butcher over the edge. The Boys, Vol. 9: The Big Ride collects issues 48-59 of the New York Times Best-Selling series by Garth Ennis, Darick Robertson, Russ Braun and John McCrea, and features all of the covers by Robertson!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999443,"hdCover":""},{"id":"0989452","title":"Капитан Америка. Две Америки","author":"Эд Брубейкер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003548005/140/a484/Ed_Brubejker__Kapitan_Amerika._Dve_Ameriki.jpg","isbn":"978-5-91878-399-3","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После ошеломляющих событий, описанных в сборнике «Капитан Америка. Возрождённый», двум героям, Стиву Роджерсу и Баки Барнсу, нужно принять решение: кто из них теперь возьмёт щит — символ американского Стража Свободы? Решение нужно принимать быстро, ведь сумасшедший Кэп из пятидесятых годов опять вступил в игру, угрожая безопасности страны изнутри. Капитан Америка и Сокол объединяются, чтобы остановить террористический заговор, который может навсегда изменить будущее свободного мира!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999442,"hdCover":""},{"id":"0989451","title":"Джокер. 80 лет знаменитому злодею","author":"","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005139480/140/04c8/__Dzhoker._80_let_znamenitomu_zlodeyu.jpg","isbn":"978-5-389-18676-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Клоун-Принц Преступного Мира, смертоносный паяц, носитель хаоса и любитель одеваться с иголочки. Его бледное лицо с кроваво-красной улыбкой является в кошмарах многим героям вселенной DC. Его происхождение окутано тайной и мифами. И сколько бы его не пробовали запереть в психушке – никакие стены не способны удержать настоящее воплощение безумия!..  В 2020 году Джокер, один из величайших когда-либо созданных злодеев, отмечает свой юбилей: вот уже 80 лет злодей сверкает своим жутким оскалом и творит бесчинства на страницах комиксов. В этом сборнике лучшие таланты современной комикс-индустрии – СКОТТ СНАЙДЕР, ДЖЕЙМС ТАЙНИОН IV, БРАЙАН АЗЗАРЕЛЛО, ДЖОК, ЭДУАРДО РИССО, ЛИ БЕРМЕХО и другие – представляют новые истории о самом страшном противнике Бэтмена и в очередной раз напоминают нам, что зло будет смеяться вечно.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999441,"hdCover":""},{"id":"0989450","title":"Удивительный Человек-Паук. Полное издание","author":"Дэвид Микелайни,Тодд МакФарлан","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002992578/140/7e74/__Udivitelnyj_ChelovekPauk._Polnoe_izdanie.jpg","isbn":"978-5-04-099063-4","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"ВАРВАРЫ","genres":["Комиксы","манга","графические романы"],"annotation":"У Микелайни и МакФарлейна Питер Паркер и Мэри Джейн Уотсон становятся стильной парой, живущей в центре Манхэттена. Авторы возвращают классических злодеев вроде Доктора Осьминога, Песочного Человека, Ящера и Зеленого Гоблина. А самое главное – они превращают Эдди Брока в нового злейшего врага Паука – жестокого Венома!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999440,"hdCover":""}]');

