FROM json_each('[{"id":"098944f","title":"Несокрушимый Халк. Том 3. Время крушить","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002311181/140/5ad5/Mark_Uejd__Nesokrushimyj_Halk._Tom_3._Vremya_krushit.jpg","isbn":"978-5-91878-189-0","publisher":"Фантастика Книжный Клуб","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отрываясь от событий Эры Альтрона, Халк отправляется на самую опасную из своих миссий, когда тайное подразделение ЩИТа, отвечающее за путешествия во времени, привлекает зелёного гиганта к спасению пространственно-временного континуума! Из-за воздействия редких флуктуаций временнóй поток рассечён, и собрать его воедино под силу лишь Халку, однако без превосходного интеллекта Брюса Бэннера, способного провести их обоих через все повороты и хитросплетения путешествий во времени, Зелёный Голиаф неизбежно исчезнет из истории. Смогут ли две части Халка мирно сосуществовать достаточно долго, чтобы выжить в суровых битвах с динозаврами, ковбоями и рыцарями Камелота? И когда Халк прибудет на место собственного провоцированного гамма-радиацией рождения, принесёт ли он себя в жертву, навсегда исчезнув из прошлого и будущего ради победы над перемещающимися во времени террористами-хронархистами?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999439,"hdCover":""},{"id":"098944e","title":"Несокрушимый Халк. Том 2. Боги и монстр","author":"Уолтер Симонсон,Марк Уэйд,Маттео Скалера","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001700238/140/7b51/__Nesokrushimyj_Halk._Tom_2._Bogi_i_monstr.jpg","isbn":"978-5-91878-164-7","publisher":"Фантастика Книжный Клуб","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Брюс Бэннер вместе со своими лаборантами отправляется в Ётунхейм, а это может означать только одно: Халку придётся сразиться с ледяными гигантами! В их стычку вмешивается Тор, но что не так с богом грома и почему он не узнаёт Халка? Ледяные гиганты стремятся вторгнуться на Землю, и ни Халк, ни Тор не способны их сдержать - героям нужна помощь, Далее Халк начинает борьбу с уличной преступностью и доказывает истинность тайной дружбы Мэтта Мёрдока с Брюсом Бэннером! Сорвиголова появляется в качестве приглашённой звезды, а Халку предстоит испытать последствия слепой ярости!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-10","rating":4,"review":"","added":9999438,"hdCover":""},{"id":"098944d","title":"Бэтмен. Черное зеркало","author":"Скотт Снайдер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004770807/140/a159/Skott_Snajder__Betmen._Chernoe_zerkalo.jpg","isbn":"978-5-389-18392-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Дик Грейсон – новый Бэтмен.  Пока Брюс Уэйн занят развитием своей новой организации супергероев, бремя по защите Готэма лежит на плечах Дика. Вот только Грейсон не узнает некогда родной город. Он стал диким, странным и… голодным. А его преступники изменились. На смену психам из Аркхема пришли криминальные умы, вроде Дилера или Тигровой Акулы. Кровожадные чудовища, продумывающие свои планы на много шагов вперед…  К тому же в город неожиданно возвращается Джим Гордон-младший – и это подкидывает лишних тревог его отцу, комиссару полиции Готэма. Мальчик, которого Брюс спас еще на заре своей деятельности, выбрал неправильный путь в жизни: он совершал нехорошие вещи и долго скрывался от своей семьи, путешествуя по миру. Но вот Джим здесь, и он уверяет своего отца и Дика, что исправился. Но так ли это на самом деле?..  «Бэтмен: Черное зеркало» – одна из лучших историй в современной эпохе Темного Рыцаря, быстро завоевавшая культовый статус. Скотт Снайдер и художники Джок и Франческо Франкавилла проделали невероятную работу – ловко оперируя элементами супергеройских комиксов и мрачных детективов, авторы создали книгу, которую должен прочитать каждый поклонник Бэтмена.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":5,"review":"","added":9999437,"hdCover":""},{"id":"098944c","title":"Несокрушимый Халк. Том 1. Агент Щита","author":"Марк Уэйд,Лайнел Френсис Ю","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001564166/140/549d/__Nesokrushimyj_Halk._Tom_1._Agent_Schita.jpg","isbn":"978-5-91878-158-6","publisher":"Фантастика Книжный Клуб","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Невероятный Халк — несокрушимая сила природы, скорее оружие, нежели человек. Брюс Бэннер — альтер эго Халка и один из одарённейших людей планеты. Вместе они — самое мощное и умное оружие. И теперь они оба работают на правительство, ведь Marvel NOW! делает из Халка агента ЩИТа! Нейтрализуя такие смертельные угрозы, как Безумный мыслитель, Пятикратный человек и Аттума, Халк из ходячего ОМП превращается в спасителя человечества. Но, даже приняв на себя роль героя, зелёный Голиаф продолжит заниматься тем, что удаётся ему лучше всего…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":4,"review":"","added":9999436,"hdCover":""},{"id":"098944b","title":"Человек-Паук. Планета Симбиотов","author":"Дэвид Микелайни","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002872963/140/2c8a/Devid_Mikelajni__ChelovekPauk._Planeta_Simbiotov.jpg","isbn":"978-5-91339-700-3","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"История","genres":["Комиксы","манга","графические романы"],"annotation":"Чувствуя растущее давление своего «тёмного другого», Эдди Брок принимает нелёгкое решение отделиться от симбиота Венома! Но вопреки его ожиданиям, разделение оборачивается полномасштабным инопланетным вторжением! Симбиоты захватывают тела людей, и Эдди приходится объединить силы с Человеком-Пауком и Алым Пауком, чтобы сорвать оккупацию Земли. А для этого им придётся отправиться на Планету Симбиотов! Но чью сторону примет симбиот Веном? Помимо всего прочего, посреди всеобщего хаоса выходит из комы Карнаж – теперь он хочет поглотить как можно больше симбиотов! Смогут ли наши герои справиться с натиском пятнадцатиметрового психопата? Встречайте новый фантастически-симбиотический блокбастер!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":3,"review":"","added":9999435,"hdCover":""},{"id":"098944a","title":"Стэн Ли. Лучшее","author":"Стэн Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003265194/140/0665/Sten_Li__Sten_Li._Luchshee.jpg","isbn":"978-5-04-103682-9","publisher":"Эксмо","pubDate":"2019","language":"Русский","series":"Классика Marvel. Лучшее","genres":["Комиксы","манга","графические романы"],"annotation":"В 1961 году Стэн Ли написал первый выпуск \"Фантастической четвёрки\" и навсегда изменил мир комиксов. Он дал читателю ощущение, что любимые персонажи настоящие, живут в соседнем квартале и, кроме периодических спасений мира, решают вполне насущные проблемы. В этой книге собраны комиксы, которые навсегда изменили правила игры и сделали Стэна Ли бессмертным.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":4.5,"review":"","added":9999434,"hdCover":""}]');
